    def start_listen():
        global globalflag,latest_input_pos,latest_output_pos,lastinputIndex,conjectures,listenstart
        if globalflag==False:
            globalflag=True
            reset_interpretations()
            latest_input_pos=0 #initializing
            latest_output_pos=0 #initializing
            lastinputIndex=0 #initializing
            conjectures=[]
            listenstart=time.time_ns()
            print('call listen')
            listen(pipe_main)
            p=mp.Process(target=conjecture,args=[pipe_conjecture,model,metadata,inputinterpretation,outputinterpretation,inputscorepositions,outputscorepositions,nextscoreposition,prevscoreposition,references])
            p.start()
    tk.Button(buttons,command=start_listen,text='start listen').grid(row=0,column=columnindex)
    columnindex+=1

    def stop_listen():
        global globalflag
        midiout.send_message([0x80,77,100])
        if globalflag==True:
            pipe_main.send([False,0,0,0,0]) #terminate conjecture process
        globalflag=False
        for n in range(120):
            midiout.send_message([0x80,n,100])
            time.sleep(0.001)
    tk.Button(buttons,command=stop_listen,text='stop listen').grid(row=0,column=columnindex)
    columnindex+=1

    def print_input():
        inputrecording=[]
        for note in inputinterpretation:
            if note['time'] is not None and note['on_off']==144:
                inputrecording+=[[note['note#'],note['time']-listenstart/1E9,int(note['vel'])]]
        print('inputrecording',inputrecording)
    tk.Button(buttons,command=print_input,text='print input onsets').grid(row=0,column=columnindex)
    columnindex+=1

    def print_output():
        outputrecording=[]
        for note in outputinterpretation:
            if note['time'] is not None and note['on_off']==144:
                outputrecording+=[[note['note#'],note['time']-listenstart/1E9,int(note['vel'])]]
        print('outputrecording',outputrecording)
    tk.Button(buttons,command=print_output,text='print output onsets').grid(row=0,column=columnindex)
    columnindex+=1

